window.GIFTS = {"catalyst":{"slug":"catalyst","name":"The Catalyst","subtitle":"The Gift of Prophecy","metaphor":{"title":"The Volcano","description":"The volcano represents the powerful, transformative force within the prophetically gifted—a divine fire that builds pressure beneath the surface until it erupts in truth-telling and catalytic change. The color Lava Red represents this molten intensity, symbolizing the heated passion for truth and the creative and destructive potential of the gift.","icon":"Flame"},"profileSummary":"The Catalyst is a visionary and pioneering force, driven by a need for truth and a passion for revolutionary transformation. This is not merely a personality trait but a sacred calling—a divine operational style that compels them to challenge the status quo, uproot broken systems, and build new, more effective ones in their place.","foundationalVerses":["Romans 12:6 - \"Having gifts that differ according to the grace given to us, let us use them: if prophecy, in proportion to our faith.\"","1 Thessalonians 5:21 - \"Test all things; hold fast what is good.\""],"descriptiveWords":["Innovative","Challenger","Assured","Discerning","Go-getting","Adventurous"],"coreFramework":{"question":"What is the truth that will unlock transformation here?","questionDescription":"The Catalyst instinctively searches for the foundational truth that, once revealed, will catalyze change. Where others see a simple conflict, the Catalyst sees a broken system and discerns the pathway to its renewal.","energizer":"Willingness to Confront Reality","energizerDescription":"Catalysts are energized by courage, not just comfort. They need to be surrounded by people willing to look at the brutal facts of a situation and act on them.","drive":"Transformation","driveDescription":"They are compelled to spark transformation and create breakthrough solutions, acting from a sense of eternal perspective while pioneering innovative approaches that revolutionize systems."},"strengths":[{"title":"Visionary Courage","description":"They possess a profound courage that enables them to speak truth to power and challenge entrenched systems that others avoid."},{"title":"Unwavering Integrity","description":"They are driven by an uncompromising commitment to integrity and an innate desire for alignment between words, actions, and motives."},{"title":"Passionate Conviction","description":"They operate from a place of deep, immovable conviction, giving them the resilience to stand for what is right, even in the face of opposition."},{"title":"Drive for Authentic Renewal","description":"Beyond simply pointing out flaws, their ultimate strength is a powerful vision for genuine renewal and the relentless drive to help build it."}],"challenges":[{"title":"A Tendency Toward Harsh Judgment","description":"Their high standards can cause them to judge others' perceived failures without sufficient grace."},{"title":"Impatience with Process","description":"Their breakneck desire for results can cause them to view other personalities as barriers to change."},{"title":"Emotional Burden and Isolation","description":"The constant awareness of what's wrong can create a heavy emotional burden, leading to cynicism and isolation if not balanced with grace."}],"leadershipStyle":{"title":"Catalytic Innovator","description":"Prophetic leaders lead through transformational vision and breakthrough thinking.","characteristics":["Disruptive Innovation","Catalytic Communication","Pioneering Spirit","Systems Transformation","Moral Courage"]},"interactions":["Be direct and willing to confront hard truths; they value courage over comfort.","Focus on the \"why\" behind a project, not just the \"what.\"","Give them problems to solve and a safe place to fail without judgment.","Don't be offended by their directness; understand it often comes from a desire to improve things."],"commission":"Jeremiah 1:10: \"See, today I appoint you over nations and kingdoms to uproot and tear down, to destroy and overthrow, to build and to plant.\""},"servant":{"slug":"servant","name":"The Servant of All","subtitle":"The Gift of Service","metaphor":{"title":"The Harvester","description":"The harvester represents the tireless, systematic work of gathering what has been planted. Like a combine harvester moving through fields with precision and endurance, those with the gift of service work with methodical excellence to meet practical needs and ensure nothing valuable is wasted.","icon":"Wrench"},"profileSummary":"The Servant of All possesses a divine compulsion to meet practical needs through tangible action and faithful work. They are the backbone of any organization, driven not by recognition but by the deep satisfaction of seeing tasks completed with excellence and people genuinely helped.","foundationalVerses":["Romans 12:7 - \"If it is serving, then serve; if it is teaching, then teach.\"","Mark 10:43-44 - \"Whoever wants to become great among you must be your servant, and whoever wants to be first must be slave of all.\""],"descriptiveWords":["Industrious","Hands-on","Consistent","Meticulous","Supportive","Conscientious"],"coreFramework":{"question":"What needs to be done, and who is doing it?","questionDescription":"The service-gifted are driven by an internal question that constantly scans their environment for practical needs and assesses whether everyone is contributing fairly.","energizer":"Visible Recognition & Shared Effort","energizerDescription":"They are energized when their practical contributions are specifically noticed and genuinely recognized, and they thrive when others step up to help.","drive":"Tangible Results","driveDescription":"They are driven by the deep satisfaction of completing a task, solving a practical problem, and seeing the high-quality result of their labor."},"strengths":[{"title":"Unwavering Dependability","description":"They possess a rare level of reliability that others can count on. When they commit to something, it gets done with excellence and on time."},{"title":"Excellence in Execution","description":"They have a natural drive for quality and attention to detail that ensures work is not just completed but completed well."},{"title":"Practical Problem-Solving","description":"They excel at finding practical, effective solutions to real-world problems and implementing them efficiently."},{"title":"Faithful Endurance","description":"They possess the perseverance to stick with tasks through completion, even when the work is difficult or unrecognized."}],"challenges":[{"title":"Tendency to Over-Commit","description":"Their desire to help can lead them to take on more than they can handle, resulting in burnout and resentment."},{"title":"Difficulty Saying No","description":"They may struggle to set healthy boundaries and prioritize their own needs when others are asking for help."},{"title":"Criticism of Others' Work Standards","description":"Their high standards for quality work can lead to frustration and criticism when others don't meet their expectations."}],"leadershipStyle":{"title":"Servant Leader","description":"Service leaders lead through humble example and dedicated support.","characteristics":["Leading by Example","Practical Problem-Solving","Supportive Infrastructure","Attention to Detail","Consistent Follow-Through"]},"interactions":["Appreciate their behind-the-scenes work and acknowledge their contributions.","Give them clear expectations and the resources they need to do excellent work.","Don't take advantage of their willingness to help; respect their time and energy.","Include them in planning so they understand how their work fits into the bigger picture."],"commission":"Mark 10:43-44: \"Whoever wants to become great among you must be your servant, and whoever wants to be first must be slave of all.\""},"erudite":{"slug":"erudite","name":"The Erudite","subtitle":"The Gift of Teaching","metaphor":{"title":"The Ancient Oak Tree","description":"The Ancient Oak represents the deep-rooted wisdom and enduring strength of the teaching gift. Like an oak that grows slowly but stands for centuries, those with the gift of teaching develop profound understanding over time and become sources of reliable wisdom for generations.","icon":"TreePine"},"profileSummary":"The Erudite carries a divine hunger for truth and understanding, called to learn with rigor and share knowledge with clarity. They are driven by an insatiable curiosity and a commitment to intellectual honesty that makes them trusted sources of wisdom and insight.","foundationalVerses":["Romans 12:7 - \"If it is serving, then serve; if it is teaching, then teach.\"","2 Timothy 2:15 - \"Study to show yourself approved to God, a worker who does not need to be ashamed and who correctly handles the word of truth.\""],"descriptiveWords":["Analytical","Thorough","Patient","Precise","Knowledgeable","Insightful"],"coreFramework":{"question":"Is this subject worthy of my intellectual energy?","questionDescription":"The Erudite filters the world through a lens of intellectual substance. Before investing their energy, they instinctively assess if a topic has sufficient depth and truth to justify the rigorous process of mastery.","energizer":"Deep Study & Genuine Curiosity from Others","energizerDescription":"They are energized by uninterrupted time for deep research and reflection. This energy is compounded when others show genuine curiosity and a sincere desire to learn what they have discovered.","drive":"To Acquire & Disseminate Knowledge","driveDescription":"They are driven by an insatiable desire to acquire a mastery-level understanding of complex subjects and feel a compulsion to disseminate that knowledge with clarity and precision."},"strengths":[{"title":"Intellectual Rigor","description":"They possess an exceptional commitment to thorough research and logical analysis that ensures their conclusions are well-founded and trustworthy."},{"title":"Patient Teaching Ability","description":"They have a natural gift for breaking down complex concepts and presenting them in ways that others can understand and apply."},{"title":"Commitment to Accuracy","description":"They are driven by a desire for precision and truth that makes them reliable sources of information and wisdom."},{"title":"Deep Curiosity","description":"They possess an insatiable hunger for learning that drives them to continuously expand their knowledge and understanding."}],"challenges":[{"title":"Analysis Paralysis","description":"Their desire for thoroughness can sometimes prevent them from taking action or making decisions in a timely manner."},{"title":"Impatience with Shallow Thinking","description":"They may become frustrated with others who don't share their commitment to intellectual rigor and deep analysis."},{"title":"Tendency to Intellectualize Emotions","description":"They may struggle to connect with others on an emotional level, preferring logical analysis over emotional processing."}],"leadershipStyle":{"title":"The Wise Teacher","description":"Erudite leaders lead through wisdom, clarity, and the intellectual development of their team. They don't just give answers; they teach people how to think.","characteristics":["Mentoring Focus","Clarity of Communication","Evidence-Based Decisions","Fostering a Learning Culture","Principled Guidance"]},"interactions":["Respect their need for time to think and research before making decisions.","Value their expertise and seek their input on complex matters.","Don't rush them into quick decisions; they need time to analyze properly.","Appreciate their commitment to accuracy and thoroughness."],"commission":"Matthew 28:19-20: \"Go therefore and make disciples of all nations... teaching them to observe all that I have commanded you.\""},"enthusiast":{"slug":"enthusiast","name":"The Enthusiast","subtitle":"The Gift of Encouragement","metaphor":{"title":"The Magnet","description":"The magnet represents the natural ability to attract and connect people through positive energy and genuine care. Like a magnet that draws metal filings into alignment, those with the gift of encouragement have a remarkable ability to draw people together and align them toward common goals.","icon":"Users"},"profileSummary":"The Enthusiast operates under a divine mandate to champion the potential in others and foster meaningful connections. They are natural connectors and motivators, driven by a genuine love for people and an unshakeable belief in their capacity to grow and succeed.","foundationalVerses":["Romans 12:8 - \"If it is to encourage, then give encouragement.\"","1 Thessalonians 5:11 - \"Therefore encourage one another and build each other up, just as in fact you are doing.\""],"descriptiveWords":["Enthusiastic","Rallying","Expressive","Affirming","Motivational","Interpersonal"],"coreFramework":{"question":"Are we building a bond?","questionDescription":"The Enthusiast constantly assesses the quality of relational connection, believing that authentic connection is the foundation for all positive growth.","energizer":"Heartfelt Connection & Shared Joy","energizerDescription":"They are energized by moments of authentic connection—shared laughter, meaningful conversation, and mutual celebration.","drive":"To Rally","driveDescription":"They are driven by an innate ability to rally people together around a shared purpose or possibility, turning individual potential into group momentum."},"strengths":[{"title":"Natural Motivational Ability","description":"They possess an extraordinary gift for inspiring others and helping them believe in their own potential and possibilities."},{"title":"Relationship Building","description":"They excel at creating meaningful connections between people and fostering environments of trust and collaboration."},{"title":"Positive Energy","description":"They bring an infectious optimism and enthusiasm that lifts the spirits of those around them and creates positive momentum."},{"title":"Ability to See Potential","description":"They have a remarkable ability to see the best in people and help them recognize and develop their own gifts and capabilities."}],"challenges":[{"title":"Avoiding Difficult Conversations","description":"Their desire to maintain positive relationships can lead them to avoid necessary but challenging conversations."},{"title":"Over-Optimism","description":"Their positive outlook can sometimes lead them to overlook real problems or minimize legitimate concerns."},{"title":"People-Pleasing Tendencies","description":"They may struggle to set boundaries or make decisions that might disappoint others, even when those decisions are necessary."}],"leadershipStyle":{"title":"Inspirational Motivator","description":"Enthusiast leaders lead through inspiration and empowerment.","characteristics":["Vision Casting","Strength-Based Development","Positive Culture Creation","Recognition and Celebration","Coaching and Mentoring","Empowerment"]},"interactions":["Appreciate their efforts to maintain positive relationships and team morale.","Help them balance optimism with realistic assessment of challenges.","Support them in having difficult conversations when necessary.","Value their ability to see potential in others and build strong teams."],"commission":"Hebrews 10:24: \"And let us consider how we may spur one another on toward love and good deeds.\""},"host":{"slug":"host","name":"The Host","subtitle":"The Gift of Giving","metaphor":{"title":"The Silo","description":"The silo represents the strategic storage and distribution of resources for maximum impact. Like a grain silo that preserves harvest abundance for future seasons, those with the gift of giving understand how to steward resources wisely and release them strategically for the greatest benefit.","icon":"Building"},"profileSummary":"The Host understands that all resources are entrusted to them for the benefit of others through strategic stewardship. They are driven not by accumulation but by multiplication—finding ways to use what they have been given to empower others and create sustainable impact.","foundationalVerses":["Romans 12:8 - \"If it is giving, then give generously.\"","Luke 6:38 - \"Give, and it will be given to you. A good measure, pressed down, shaken together and running over, will be poured into your lap. For with the measure you use, it will be measured to you.\""],"descriptiveWords":["Generous","Multiplier","Hospitable","Prudent","Empowering","Abundant"],"coreFramework":{"question":"How are we stewarding our resources?","questionDescription":"The Host constantly evaluates how they and others are managing what they've been entrusted with, assessing whether resources are being used wisely and strategically.","energizer":"Fruitful Impact & Expressed Gratitude","energizerDescription":"Hosts are energized when they see their resources making a real, tangible difference in others' lives and when their thoughtful giving is met with genuine gratitude.","drive":"To Steward & Multiply","driveDescription":"They are driven to create, manage, and multiply resources so they can give more generously and effectively, and to help others become good stewards as well."},"strengths":[{"title":"Strategic Generosity","description":"They possess an exceptional ability to give in ways that create maximum impact and empower others to succeed and give in return."},{"title":"Resource Wisdom","description":"They have a natural understanding of how to manage, preserve, and multiply resources for long-term benefit rather than short-term gratification."},{"title":"Empowerment Focus","description":"They excel at using their resources to empower others, creating opportunities for people to develop their own capabilities and become successful."},{"title":"Multiplication Mindset","description":"They think in terms of creating systems and opportunities that multiply impact rather than simply meeting immediate needs."}],"challenges":[{"title":"Tendency to Control Outcomes","description":"Their strategic approach to giving can sometimes lead them to try to control how their gifts are used rather than trusting the recipients."},{"title":"Difficulty with Spontaneous Giving","description":"Their preference for strategic planning can make it challenging for them to respond to immediate, unplanned needs with flexibility."},{"title":"Judgment of Poor Stewardship","description":"They may become frustrated with others who don't share their commitment to wise resource management and strategic thinking."}],"leadershipStyle":{"title":"The Steward Leader","description":"Host leaders lead through resource provision and strategic investment.","characteristics":["Resource Provision","Strategic Investment","Opportunity Creation","Welcoming Culture","Empowerment Focus","Stewardship Modeling"]},"interactions":["Respect their desire to understand how resources will be used before committing.","Show them the long-term impact and multiplication potential of projects.","Don't pressure them for immediate decisions; they need time to consider strategic implications.","Appreciate their commitment to wise stewardship and empowerment of others."],"commission":"Acts 20:35: \"It is more blessed to give than to receive.\""},"strategist":{"slug":"strategist","name":"The Strategist","subtitle":"The Gift of Leadership","metaphor":{"title":"The Ship's Helm","description":"The ship's helm represents the steady, purposeful guidance that keeps an organization moving toward its destination despite changing winds and currents. Like a skilled helmsman who reads both the immediate conditions and the distant horizon, those with the gift of leadership navigate toward long-term vision while managing present realities.","icon":"Compass"},"profileSummary":"The Strategist carries a divine capacity to see future possibilities and architect the systems required to make them reality. They are natural visionaries and systematic builders, driven by the ability to envision what could be and the determination to create the pathways to achieve it.","foundationalVerses":["Romans 12:8 - \"If it is to lead, do it diligently.\"","Proverbs 29:18 - \"Where there is no vision, the people perish.\""],"descriptiveWords":["Decisive","Goal-oriented","Authoritative","Systematic","Developmental","Architectural"],"coreFramework":{"question":"Where are we going, and what is the best way to get there?","questionDescription":"The Strategist sees the world through a lens of vision and execution, instinctively assessing the ultimate goal and then architecting the most effective path to achieve it.","energizer":"Team Alignment & Measurable Progress","energizerDescription":"They are energized when the team is aligned with the vision and working together cohesively. Seeing measurable progress toward clear objectives fuels their drive.","drive":"To Architect Success","driveDescription":"They are compelled to provide direction, create order from chaos, and build systems that produce sustainable excellence, developing people and frameworks that succeed long-term."},"strengths":[{"title":"Visionary Thinking","description":"They possess an exceptional ability to envision future possibilities and see the big picture in ways that others cannot."},{"title":"Systems Architecture","description":"They excel at designing and implementing systematic approaches that turn visions into achievable, step-by-step realities."},{"title":"Strategic Decision-Making","description":"They have a natural ability to make decisions that align with long-term objectives rather than just addressing immediate concerns."},{"title":"Development of Others","description":"They are gifted at recognizing potential in others and creating opportunities for people to grow and contribute to larger objectives."}],"challenges":[{"title":"Impatience with Details","description":"Their focus on big-picture vision can sometimes lead them to overlook important details or become impatient with necessary but mundane tasks."},{"title":"Tendency to Overwhelm Others","description":"Their ambitious visions and systematic approaches can sometimes feel overwhelming or unrealistic to others who don't share their strategic perspective."},{"title":"Difficulty with Immediate Needs","description":"Their long-term focus can make it challenging for them to respond effectively to immediate, urgent needs that don't fit into their strategic plans."}],"leadershipStyle":{"title":"Strategic Architect","description":"Strategist leaders lead through vision, planning, and systematic execution.","characteristics":["Visionary Planning","Strategic Thinking","System Building","Team Development","Goal Achievement"]},"interactions":["Respect their need to understand how immediate tasks fit into the bigger picture.","Support their long-term thinking and don't pressure them for quick fixes to complex problems.","Help them communicate their vision in ways that others can understand and embrace.","Appreciate their commitment to systematic development and sustainable growth."],"commission":"Proverbs 29:18: \"Where there is no vision, the people perish; but blessed is he who keeps the law.\""},"lover":{"slug":"lover","name":"The Lover","subtitle":"The Gift of Mercy","metaphor":{"title":"The Heart","description":"The heart represents the life-giving center of compassion and emotional healing. Like the physical heart that pumps life-sustaining blood throughout the body, those with the gift of mercy circulate love, empathy, and healing throughout their communities, bringing emotional health and restoration.","icon":"Heart"},"profileSummary":"The Lover carries a divine heart that beats with compassion for the suffering and wounded, bringing healing presence wherever pain exists. They are natural empaths and healers, driven by an overwhelming desire to comfort, protect, and restore those who are hurting.","foundationalVerses":["Romans 12:8 - \"If it is to show mercy, do it cheerfully.\"","2 Corinthians 1:3-4 - \"Praise be to the God and Father of our Lord Jesus Christ, the Father of compassion and the God of all comfort, who comforts us in all our troubles, so that we can comfort those in any trouble with the comfort we ourselves receive from God.\""],"descriptiveWords":["Empathetic","Accepting","Nurturing","Rescuing","Gentle","Patient"],"coreFramework":{"question":"Is this a safe place for the heart?","questionDescription":"The Lover constantly assesses the emotional climate of their surroundings, driven to create environments where hearts can be vulnerable without fear of judgment.","energizer":"Emotional Safety & Unconditional Acceptance","energizerDescription":"Lovers are energized by authentic, intimate relationships where they are loved and accepted for who they are, not just what they do. They thrive in environments of emotional honesty and gentle communication where they can offer and receive comfort freely.","drive":"To Comfort, Rescue, and Shield","driveDescription":"They are compelled to bring emotional comfort to those who are hurting, rescue those trapped in pain, and shield the vulnerable from further harm."},"strengths":[{"title":"Deep Empathy","description":"They possess an extraordinary ability to understand and share in the emotions of others, creating profound connections and offering genuine comfort."},{"title":"Healing Presence","description":"They have a natural gift for creating safe emotional spaces where people can process pain and begin to heal from their wounds."},{"title":"Unconditional Acceptance","description":"They excel at offering love and acceptance without judgment, helping others feel valued and worthy regardless of their circumstances."},{"title":"Protective Instincts","description":"They are naturally driven to protect others from emotional harm and to intervene when they see injustice or cruelty."}],"challenges":[{"title":"Emotional Overwhelm","description":"Their deep empathy can lead them to absorb others' pain to an unhealthy degree, resulting in emotional exhaustion and burnout."},{"title":"Difficulty with Boundaries","description":"Their desire to help everyone can make it challenging for them to set healthy limits and protect their own emotional well-being."},{"title":"Avoidance of Necessary Confrontation","description":"Their preference for harmony and emotional safety can lead them to avoid necessary but difficult conversations or decisions."}],"leadershipStyle":{"title":"Compassionate Shepherd","description":"Mercy leaders lead through care, understanding, and creating safe environments.","characteristics":["Pastoral Care","Safe Environment Creation","Patient Development","Conflict Resolution","Supportive Presence"]},"interactions":["Create emotionally safe environments where they can be vulnerable without judgment.","Appreciate their gift for understanding and comforting others in pain.","Help them maintain healthy boundaries and avoid emotional overwhelm.","Support them in learning to balance mercy with necessary accountability."],"commission":"Luke 6:36: \"Be merciful, just as your Father is merciful.\""}};
window.ARCHETYPES = [{"num":1,"name":"The Apex Visionary","slug":"apex-visionary","gifts":["catalyst","erudite","strategist"],"essence":"To pioneer a transformative possibility, establish its intellectual credibility, and design the long-range architecture through which it can reshape the future.","section":"Section 1: The Apex Visionaries (Pure “Why” Triad)","axisSignature":"3 Why","websiteSummary":"The Apex Visionary pioneers a transformative possibility, establishes its intellectual credibility, and designs the long-range architecture required to sustain it. At their best, they create rigorous frameworks for a better future. Under stress, innovation becomes criticism, knowledge becomes superiority, and strategy treats people as elements in a system they were never invited to shape.","sigStrengthName":"Paradigm Architecture","sigStrengthDesc":"The Apex Visionary can integrate breakthrough insight, intellectual rigor, and long-range design into a comprehensive alternative.","sigParadox":"Designing a future for people without losing contact with the people who must inhabit it","devQuestion":"Can I invite people into the unfinished process rather than presenting a completed future they were never allowed to shape?","formationPractices":["Explain the vision without specialized language.","Invite a Servant, Host, Enthusiast, or Lover to critique the plan.","Test a small part of the model before expanding it.","Ask affected people to reshape the architecture.","Practice saying, “I may be wrong.”","Distinguish foundational principles from preferred designs.","Spend time with frontline practitioners.","Communicate uncertainty alongside conviction.","Measure human flourishing, not only conceptual coherence and strategic progress."],"leadershipStyleName":"The Paradigm Architect"},{"num":2,"name":"The Principled Reformer","slug":"principled-reformer","gifts":["catalyst","servant","erudite"],"essence":"To challenge an inadequate system, establish the truth about what must change, and build a practical alternative whose integrity can be demonstrated through real work.","section":"Section 2: The Principled Architects (Vision & Action Hybrids)","axisSignature":"2 Why · 1 How","websiteSummary":"The Principled Reformer challenges an inadequate system, establishes the truth about what must change, and builds a practical alternative. At their best, they make reform credible through rigorous evidence and demonstrated work. Under stress, conviction becomes criticism, precision becomes contempt, and service becomes resentful martyrdom.","sigStrengthName":"Demonstrated Reform","sigStrengthDesc":"The Principled Reformer can connect moral or conceptual challenge with meticulous evidence and a working alternative.","sigParadox":"Refusing to compromise the principle without demanding perfection from every person","devQuestion":"Can I remain uncompromising about the essential principle while remaining patient with imperfect people and iterative progress?","formationPractices":["Define which principle is truly nonnegotiable.","Identify which standards are preferences.","Build a limited prototype before completing the entire case.","Ask frontline participants to critique the reform.","Delegate a meaningful portion of implementation.","State needs before resentment develops.","Celebrate progress publicly.","Practice correcting without contempt.","Rest before exhaustion becomes a moral identity."],"leadershipStyleName":"The Evidence-Based Reformer"},{"num":3,"name":"The Scholarly Investor","slug":"scholarly-investor","gifts":["catalyst","erudite","host"],"essence":"To recognize transformative potential, investigate whether it is genuinely credible, and direct resources toward the ideas most capable of producing meaningful change.","section":"Section 2: The Principled Architects (Vision & Action Hybrids)","axisSignature":"2 Why · 1 How","websiteSummary":"The Scholarly Investor recognizes transformative possibilities, rigorously evaluates their credibility, and directs resources toward the ideas most likely to produce meaningful change. At their best, they unite courageous innovation with responsible stewardship. Under stress, analysis delays action, provision becomes control, and the desire to eliminate risk prevents worthy experiments from receiving a chance.","sigStrengthName":"Evidence-Informed Innovation Investment","sigStrengthDesc":"The Scholarly Investor can move meaningful resources behind an unconventional idea without abandoning discernment.","sigParadox":"Practicing due diligence without using analysis to eliminate every meaningful risk","devQuestion":"Can I distinguish responsible uncertainty from irresponsible risk and act before certainty is available?","formationPractices":["Create explicit investment criteria.","Set a deadline for due diligence.","Use staged investments to test uncertainty.","Include people affected by the innovation in evaluation.","Name risks openly rather than attempting to eliminate them.","Fund one credible initiative outside your familiar network.","Define decision rights before releasing resources.","Treat failed experiments as potential learning assets.","Give something meaningful without controlling the outcome."],"leadershipStyleName":"The Innovation Steward"},{"num":4,"name":"The Insightful Inspirer","slug":"insightful-inspirer","gifts":["catalyst","erudite","enthusiast"],"essence":"To discover a transformative insight, establish its credibility, and communicate it through a compelling narrative that awakens hope and participation.","section":"Section 3: The Visionary Mentors (Vision & Heart Hybrids)","axisSignature":"2 Why · 1 Who","websiteSummary":"The Insightful Inspirer discovers transformative insight, establishes its credibility, and communicates it through a narrative that awakens hope and participation. At their best, they make rigorous innovation accessible and compelling. Under stress, communication becomes performance, complexity is sacrificed for approval, and emotional impact is mistaken for lasting transformation.","sigStrengthName":"Compelling Translation","sigStrengthDesc":"The Insightful Inspirer can move an idea from specialist knowledge into public imagination.","sigParadox":"Making truth compelling without reshaping it to preserve applause","devQuestion":"Can I remain faithful to the truth when accuracy reduces immediate enthusiasm or approval?","formationPractices":["Separate facts, interpretations, and aspirations.","Ask a subject-matter expert to review the message.","Name one cost or limitation publicly.","Define the action the message is inviting.","Stay involved after the speaking moment.","Seek feedback from people who were not persuaded.","Practice communicating without dramatic language.","Resist using audience emotion as evidence of truth.","Build a team that can implement what you inspire."],"leadershipStyleName":"The Transformational Communicator"},{"num":5,"name":"The Compassionate Sage","slug":"compassionate-sage","gifts":["catalyst","erudite","lover"],"essence":"To recognize the truth that could unlock inner transformation, understand it deeply, and communicate it with enough compassion that it can be received without sacrificing either honesty or dignity.","section":"Section 3: The Visionary Mentors (Vision & Heart Hybrids)","axisSignature":"2 Why · 1 Who","websiteSummary":"The Compassionate Sage recognizes the truth that could unlock inner transformation, understands it deeply, and communicates it with compassion. At their best, they create enough safety for difficult truth to become a doorway to freedom. Under stress, insight becomes analysis, challenge becomes harshness, and compassion becomes silence or emotional absorption.","sigStrengthName":"Transformative Wisdom","sigStrengthDesc":"The Compassionate Sage can name difficult realities while helping people experience the truth as an invitation rather than a verdict.","sigParadox":"Creating enough safety for truth without making safety dependent upon avoiding truth","devQuestion":"Can I trust that honest, compassionate challenge may create temporary discomfort without destroying the relationship?","formationPractices":["Ask, “Would you like reflection, comfort, or challenge?”","Distinguish what you observed from what you inferred.","Offer interpretations with humility.","Say the essential truth in one sentence.","Allow silence after speaking.","Practice remaining connected when someone disagrees.","Establish boundaries around emotional responsibility.","Attend to personal wounds before interpreting others.","Repair delivery without abandoning the truth.","Ask whether the insight opens freedom or merely demonstrates perception."],"leadershipStyleName":"The Transformational Counselor"},{"num":6,"name":"The Visionary Implementer","slug":"visionary-implementer","gifts":["catalyst","servant","strategist"],"essence":"To innovate a better way, architect a workable path, and personally help turn the vision into reality.","section":"Section 2: The Principled Architects (Vision & Action Hybrids)","axisSignature":"2 Why · 1 How","websiteSummary":"The Visionary Implementer sees a better future, designs the system that can reach it, and does the practical work required to make it real. At their best, they create executable innovation. Under stress, they over-function, over-control, and carry work that should belong to others.","sigStrengthName":"Executable Innovation","sigStrengthDesc":"The Visionary Implementer can see something new without losing sight of what it will take to build it. They often become:","sigParadox":"Building the future without carrying the entire future alone","devQuestion":"Can I remain responsible for the vision without becoming responsible for every task?","formationPractices":["Delegate an outcome, not merely a task.","Ask, “Does this need to be redesigned, or merely completed?”","Limit active innovations to a sustainable number.","Invite affected people into the design process.","Practice receiving help without correcting how it is offered.","Celebrate shared ownership more than personal productivity."],"leadershipStyleName":"The Builder of New Systems"},{"num":7,"name":"The Resourced Revolutionary","slug":"resourced-revolutionary","gifts":["catalyst","host","strategist"],"essence":"To pioneer transformative possibilities, gather the resources they require, and build structures capable of sustaining them.","section":"Section 2: The Principled Architects (Vision & Action Hybrids)","axisSignature":"2 Why · 1 How","websiteSummary":"The Resourced Revolutionary pioneers transformative possibilities, gathers what they need, and builds structures capable of carrying them into the future. At their best, they turn resources into enduring service. Under stress, stewardship can become control and mission can become empire.","sigStrengthName":"Sustainable Transformation","sigStrengthDesc":"","sigParadox":"Stewarding power without being possessed by it","devQuestion":"Do I possess these resources for the mission, or has the mission become a justification for possessing them?","formationPractices":["Establish independent accountability over money and authority.","Give anonymously when possible.","Ask who gains agency through each investment.","Include human flourishing among success metrics.","Invite critique from people who do not depend upon your approval.","Periodically identify what should be released rather than expanded."],"leadershipStyleName":"The Institution-Building Steward"},{"num":8,"name":"The Galvanizing Leader","slug":"galvanizing-leader","gifts":["catalyst","enthusiast","strategist"],"essence":"To innovate a better future, inspire people to believe in it, and organize collective action that makes it possible.","section":"Section 3: The Visionary Mentors (Vision & Heart Hybrids)","axisSignature":"2 Why · 1 Who","websiteSummary":"The Galvanizing Leader sees a better future, helps people believe in it, and organizes collective movement toward it. At their best, they awaken courageous participation. Under stress, inspiration becomes urgency, strategy becomes pressure, and belonging can become conditional upon agreement.","sigStrengthName":"Mobilized Possibility","sigStrengthDesc":"","sigParadox":"Mobilizing people without pressuring them","devQuestion":"Am I inviting willing participation, or using hope, urgency, and belonging to produce compliance?","formationPractices":["Invite someone to identify the weaknesses in your vision.","Create legitimate pathways for disagreement.","Communicate costs as clearly as benefits.","Practice presence without recruitment.","Celebrate faithful limits, not only extraordinary commitment.","Ask whether people are becoming more free through your leadership.","Allow seasons of consolidation rather than creating continuous urgency."],"leadershipStyleName":"The Mobilizing Visionary"},{"num":9,"name":"The Protective Visionary","slug":"protective-visionary","gifts":["catalyst","strategist","lover"],"essence":"To pioneer necessary transformation, lead it decisively, and protect the dignity and well-being of the people affected by it.","section":"Section 3: The Visionary Mentors (Vision & Heart Hybrids)","axisSignature":"2 Why · 1 Who","websiteSummary":"The Protective Visionary pioneers necessary change while guarding the dignity of those affected by it. At their best, they unite courage, strategic direction, and humane care. Under stress, compassion becomes over-responsibility and protection becomes control.","sigStrengthName":"Humane Transformation","sigStrengthDesc":"","sigParadox":"Protecting people without protecting them from every necessary difficulty","devQuestion":"Am I protecting dignity, or preventing people from experiencing the difficulty required for development?","formationPractices":["Ask before rescuing.","Define what belongs to your responsibility and what does not.","Build support structures rather than becoming the support structure.","Allow honest lament without immediately fixing it.","Invite vulnerable people into decision-making.","Practice boundaries as a form of sustainable love.","Measure whether care is increasing another person’s agency."],"leadershipStyleName":"The Transformational Protector"},{"num":10,"name":"The Master Craftsman","slug":"master-craftsman","gifts":["servant","erudite","strategist"],"essence":"To master what is true, design what will work, and execute it with disciplined excellence.","section":"Section 2: The Principled Architects (Vision & Action Hybrids)","axisSignature":"2 Why · 1 How","websiteSummary":"The Master Craftsman understands deeply, designs intelligently, and builds with disciplined excellence. At their best, they transform knowledge into dependable systems and skilled work. Under stress, excellence becomes perfectionism, expertise becomes superiority, and others are denied room to learn.","sigStrengthName":"Integrated Mastery","sigStrengthDesc":"","sigParadox":"Pursuing excellence without making perfection the price of participation","devQuestion":"Can I preserve excellence while allowing apprenticeship, experimentation, and human limitation?","formationPractices":["Define the purpose before establishing the standard.","Teach one person to perform a task you usually retain.","Submit unfinished work for feedback.","Identify where excellence matters most—and where adequacy is sufficient.","Celebrate another person’s progress before correcting remaining flaws.","Practice learning publicly.","Complete selected projects without one final round of refinement."],"leadershipStyleName":"The Architect of Excellence"},{"num":11,"name":"The Prudent Architect","slug":"prudent-architect","gifts":["erudite","host","strategist"],"essence":"To build enduring, well-resourced institutions upon sound knowledge, wise stewardship, and long-range strategic design.","section":"Section 2: The Principled Architects (Vision & Action Hybrids)","axisSignature":"2 Why · 1 How","websiteSummary":"The Prudent Architect combines deep research, wise provision, and long-range strategy to build institutions that endure. At their best, prudence enables faithful action. Under stress, caution becomes control and the institution’s machinery eclipses the people it exists to serve.","sigStrengthName":"Durable Stewardship","sigStrengthDesc":"The Prudent Architect can create institutions that remain stable through changing leadership, economic pressures, and cultural transitions.","sigParadox":"Preserving the mission without preserving the machinery","devQuestion":"Can I preserve what is essential while allowing structures that once served the mission to change or end?","formationPractices":["Establish a deadline before beginning research.","Fund a worthy initiative that includes manageable uncertainty.","Review which policies no longer serve the mission.","Include qualitative human outcomes alongside financial metrics.","Practice generosity without controlling every detail.","Create a process for retiring obsolete systems.","Invite challenge from someone outside the institutional culture."],"leadershipStyleName":"The Institutional Steward"},{"num":12,"name":"The Engaging Mentor","slug":"engaging-mentor","gifts":["erudite","enthusiast","strategist"],"essence":"To awaken growth by combining credible knowledge, relational encouragement, and a clear developmental path.","section":"Section 3: The Visionary Mentors (Vision & Heart Hybrids)","axisSignature":"2 Why · 1 Who","websiteSummary":"The Engaging Mentor combines deep understanding, inspiring connection, and strategic guidance to help people grow. At their best, they make development clear, hopeful, and personally owned. Under stress, mentoring becomes management and people begin to feel like projects.","sigStrengthName":"Activated Development","sigStrengthDesc":"","sigParadox":"Guiding growth without scripting another person’s life","devQuestion":"Can I champion another person’s growth without needing to author it?","formationPractices":["Ask, “Do you want listening, advice, or coaching?”","Spend an entire conversation asking questions without teaching.","Let the learner define the desired outcome.","Name potential without prescribing identity.","Bless a person’s path when it differs from your recommendation.","Measure mentoring success by growing autonomy.","Invest in one slow, unglamorous developmental relationship."],"leadershipStyleName":"The Developmental Guide"},{"num":13,"name":"The Wise Shepherd","slug":"wise-shepherd","gifts":["erudite","strategist","lover"],"essence":"To guide people with sound wisdom, compassionate presence, and a clear path toward wholeness and purposeful action.","section":"Section 3: The Visionary Mentors (Vision & Heart Hybrids)","axisSignature":"2 Why · 1 Who","websiteSummary":"The Wise Shepherd combines deep understanding, strategic direction, and compassionate presence. At their best, they help people feel safe enough to move toward wholeness. Under stress, care becomes over-responsibility, analysis delays action, and guidance becomes quietly controlling.","sigStrengthName":"Compassionate Discernment","sigStrengthDesc":"","sigParadox":"Caring deeply without carrying people indefinitely","devQuestion":"Can I offer wise and compassionate guidance without taking ownership of another person’s choices?","formationPractices":["Make a compassionate decision before universal agreement is available.","State expectations without excessive explanation.","Ask whether a person needs empathy, guidance, or accountability.","Practice allowing disappointment without repairing it prematurely.","Establish limits around emotional availability.","Build support networks rather than becoming the sole support.","Notice when analysis is replacing emotional presence."],"leadershipStyleName":"The Pastoral Strategist"},{"num":14,"name":"The Practical Revolutionary","slug":"practical-revolutionary","gifts":["catalyst","servant","host"],"essence":"To pioneer a tangible alternative to what is broken by combining bold innovation, hands-on service, and generous provision.","section":"Section 4: The Bedrock Builders (Action-Dominant Triads)","axisSignature":"1 Why · 2 How","websiteSummary":"The Practical Revolutionary challenges inadequate systems by building and resourcing a tangible alternative. At their best, they turn innovation into practical hope. Under stress, courage becomes criticism, service becomes martyrdom, and generosity becomes control.","sigStrengthName":"Embodied Innovation","sigStrengthDesc":"","sigParadox":"Building a better future without becoming its exhausted martyr","devQuestion":"Can I remain deeply committed without proving the vision through self-exhaustion?","formationPractices":["Require at least one co-owner before launching something new.","Set a time, resource, and energy limit for the prototype.","Ask the people affected what they actually need.","Receive help without redoing it.","Practice anonymous generosity.","Build rest into the operating model.","Review whether innovation is increasing community capacity or founder dependence."],"leadershipStyleName":"The Hands-On Innovator"},{"num":15,"name":"The Faithful Steward","slug":"faithful-steward","gifts":["servant","erudite","host"],"essence":"To care for entrusted people, responsibilities, and resources with knowledgeable diligence, practical wisdom, and trustworthy generosity.","section":"Section 4: The Bedrock Builders (Action-Dominant Triads)","axisSignature":"1 Why · 2 How","websiteSummary":"The Faithful Steward combines careful understanding, diligent work, and responsible generosity. At their best, they make entrusted resources more fruitful. Under stress, diligence becomes over-functioning, accuracy becomes criticism, and stewardship becomes gatekeeping.","sigStrengthName":"Trustworthy Provision","sigStrengthDesc":"","sigParadox":"Protecting what is entrusted without gripping it too tightly","devQuestion":"Can I care responsibly for what is entrusted while remembering that it was entrusted for a purpose?","formationPractices":["Give something meaningful without controlling how it is used.","Teach another person a responsibility you usually retain.","Publish clear standards rather than enforcing private expectations.","Differentiate essential accountability from personal preference.","Allow one recoverable mistake without taking the responsibility back.","Ask for appreciation directly rather than serving resentfully.","Review whether accumulated resources are fulfilling their intended purpose."],"leadershipStyleName":"The Trustworthy Custodian"},{"num":16,"name":"The Joyful Benefactor","slug":"joyful-benefactor","gifts":["servant","enthusiast","host"],"essence":"To create generous communities of belonging through practical service, contagious joy, and abundant hospitality.","section":"Section 4: The Bedrock Builders (Action-Dominant Triads)","axisSignature":"2 How · 1 Who","websiteSummary":"The Joyful Benefactor combines practical service, generous provision, and contagious warmth to create communities of belonging. At their best, they make people feel genuinely welcomed and celebrated. Under stress, hospitality becomes performance, service becomes exhaustion, and giving begins to carry hidden expectations.","sigStrengthName":"Celebratory Hospitality","sigStrengthDesc":"","sigParadox":"Creating belonging without performing for belonging","devQuestion":"Can I believe that I belong even when I am not the person making belonging possible for everyone else?","formationPractices":["Attend an event without helping organize it.","Ask directly for assistance.","Establish a hospitality budget before making plans.","Create one intentionally simple gathering.","Allow someone else to host in a different style.","Welcome people who cannot reciprocate.","Notice when celebration is being used to avoid grief or conflict."],"leadershipStyleName":"The Community Host"},{"num":17,"name":"The Master Provider","slug":"master-provider","gifts":["servant","host","strategist"],"essence":"To build reliable systems that anticipate, organize, and provide for a community’s practical needs over time.","section":"Section 4: The Bedrock Builders (Action-Dominant Triads)","axisSignature":"1 Why · 2 How","websiteSummary":"The Master Provider builds and maintains the systems that keep communities supplied, organized, and functioning. At their best, they create dependable provision that outlasts them. Under stress, competence becomes control and the system becomes dependent upon their exhaustion.","sigStrengthName":"Sustainable Provision","sigStrengthDesc":"","sigParadox":"Becoming essential without becoming indispensable","devQuestion":"Can I build a system people can depend upon without building a system that depends entirely upon me?","formationPractices":["Take a planned absence and observe what breaks.","Document one critical process each week.","Assign both responsibility and decision-making authority.","Ask whether each control addresses an actual risk.","Let another person solve a problem differently.","Build succession into every major role.","Measure the operation’s resilience without your intervention."],"leadershipStyleName":"The Operational Architect"},{"num":18,"name":"The Tender Provider","slug":"tender-provider","gifts":["servant","host","lover"],"essence":"To translate compassion into tangible care through attentive service, generous provision, and emotionally present love.","section":"Section 4: The Bedrock Builders (Action-Dominant Triads)","axisSignature":"2 How · 1 Who","websiteSummary":"The Tender Provider turns empathy into practical, generous care. At their best, they help people feel emotionally seen and tangibly supported. Under stress, compassion becomes over-responsibility, generosity creates dependence, and the caregiver disappears beneath the needs of others.","sigStrengthName":"Embodied Compassion","sigStrengthDesc":"","sigParadox":"Meeting needs without making need the basis of relationship","devQuestion":"Can I help another person become strong enough to need less from me?","formationPractices":["Ask before helping.","Define the scope and duration of assistance.","Build a team around recurring needs.","Practice receiving without immediate reciprocation.","Leave one nonessential need for another person to meet.","Track personal emotional and physical capacity.","Ask whether the care increases dignity and agency."],"leadershipStyleName":"The Compassionate Provider"},{"num":19,"name":"The Compassionate Agitator","slug":"compassionate-agitator","gifts":["catalyst","enthusiast","lover"],"essence":"To awaken people to suffering, imagine a more humane possibility, and rally a community toward courageous, compassionate transformation.","section":"Section 5: The Heart-Centered Connectors (Connection-Dominant Triads)","axisSignature":"1 Why · 2 Who","websiteSummary":"The Compassionate Agitator feels the human cost of what is broken, challenges the assumptions sustaining it, and rallies people toward a more humane possibility. At their best, they transform compassion into moral imagination and constructive change. Under stress, challenge becomes condemnation, urgency becomes emotional pressure, and belonging becomes conditional upon agreement.","sigStrengthName":"Mobilized Compassion","sigStrengthDesc":"","sigParadox":"Awakening conscience without weaponizing shame","devQuestion":"Can I confront complicity while continuing to believe in people’s capacity to change?","formationPractices":["State the desired alternative before issuing the critique.","Ask affected people how they want their stories represented.","Practice one-on-one dialogue with a hesitant potential ally.","Distinguish urgency from emotional escalation.","Create spaces where honest questions do not threaten belonging.","Limit advocacy exposure when the nervous system is overwhelmed.","Identify one practical experiment that embodies the desired future.","Pray for or humanize someone positioned as an opponent."],"leadershipStyleName":"The Humane Change-Maker"},{"num":20,"name":"The Devoted Caretaker","slug":"devoted-caretaker","gifts":["servant","enthusiast","lover"],"essence":"To surround people with holistic care through practical help, uplifting encouragement, and deeply empathetic presence.","section":"Section 5: The Heart-Centered Connectors (Connection-Dominant Triads)","axisSignature":"1 How · 2 Who","websiteSummary":"The Devoted Caretaker combines empathy, encouragement, and practical service to offer whole-person care. At their best, people feel deeply seen, strengthened, and supported. Under stress, caregiving becomes identity, encouragement avoids pain, and service becomes a way to secure love.","sigStrengthName":"Whole-Person Care","sigStrengthDesc":"","sigParadox":"Loving through service without making service the price of being loved","devQuestion":"Can I receive love when I have done nothing to earn it and cannot make anyone feel better?","formationPractices":["Wait to be asked before solving a nonurgent problem.","Ask, “Would you like empathy, encouragement, or practical help?”","Receive one act of care without immediately reciprocating.","State a personal need directly.","Establish clear limits around availability.","Let someone remain disappointed without abandoning the boundary.","Practice sitting with pain without trying to brighten it.","Develop relationships not organized around caregiving."],"leadershipStyleName":"The Nurturing Supporter"},{"num":21,"name":"The Affectionate Counselor","slug":"affectionate-counselor","gifts":["erudite","enthusiast","lover"],"essence":"To create a safe and hopeful relationship in which emotional experience is deeply understood, wise insight becomes accessible, and people discover their own path toward growth.","section":"Section 5: The Heart-Centered Connectors (Connection-Dominant Triads)","axisSignature":"1 Why · 2 Who","websiteSummary":"The Affectionate Counselor combines emotional attunement, wise understanding, and hopeful encouragement. At their best, people feel deeply seen and gently strengthened. Under stress, empathy becomes absorption, insight becomes over-analysis, and helping becomes a way to secure relational significance.","sigStrengthName":"Hopeful Insight","sigStrengthDesc":"","sigParadox":"Understanding another person without absorbing or defining them","devQuestion":"Can I offer understanding without turning another person into my interpretation of them?","formationPractices":["Ask permission before offering an interpretation.","Use phrases such as, “I wonder whether…” rather than, “What is happening is…”","Spend a conversation offering presence without advice.","Establish a ritual for releasing emotional burdens after care conversations.","Allow another person to reject your interpretation.","Receive support without becoming the counselor.","Notice when encouragement is moving too quickly past grief.","Cultivate relationships based on mutuality rather than helping."],"leadershipStyleName":"The Relational Interpreter"},{"num":22,"name":"The Lavish Celebrant","slug":"lavish-celebrant","gifts":["enthusiast","host","lover"],"essence":"To create beautiful, generous experiences in which people feel cherished, connected, and joyfully welcomed into belonging.","section":"Section 5: The Heart-Centered Connectors (Connection-Dominant Triads)","axisSignature":"1 How · 2 Who","websiteSummary":"The Lavish Celebrant creates beautiful, generous experiences in which people feel cherished and connected. At their best, celebration makes belonging tangible. Under stress, hospitality becomes performance, generosity seeks emotional repayment, and joy leaves little room for grief or difference.","sigStrengthName":"Embodied Belonging","sigStrengthDesc":"","sigParadox":"Creating joy for others without needing their joy to validate you","devQuestion":"Can I offer celebration freely without needing the room’s delight to prove my worth or the event’s success?","formationPractices":["Host a simple gathering with minimal production.","Set the budget before imagining the experience.","Allow another person to shape the event.","Welcome someone who cannot reciprocate socially or materially.","Create room for lament within communal celebration.","Participate as a guest in something you did not create.","Receive criticism without immediately repairing the experience.","Practice being present after the event’s activity ends."],"leadershipStyleName":"The Curator of Belonging"},{"num":23,"name":"The Encouraging Shepherd","slug":"encouraging-shepherd","gifts":["enthusiast","strategist","lover"],"essence":"To guide people toward a shared purpose by creating a culture of encouragement, emotional safety, and clear developmental direction.","section":"Section 5: The Heart-Centered Connectors (Connection-Dominant Triads)","axisSignature":"1 Why · 2 Who","websiteSummary":"The Encouraging Shepherd leads people toward shared purpose through hope, emotional safety, and clear direction. At their best, belonging and accountability strengthen one another. Under stress, encouragement replaces correction, care becomes over-accommodation, and direction becomes indirect control.","sigStrengthName":"Safe Mobilization","sigStrengthDesc":"The Encouraging Shepherd can create cultures in which people feel secure enough to take risks, receive guidance, and contribute meaningfully.","sigParadox":"Creating safety without protecting people from accountability","devQuestion":"Can I preserve belonging while clearly naming what growth, responsibility, and repair require?","formationPractices":["Pair every affirmation with one clear developmental invitation.","Address concerns before frustration accumulates.","State expectations behaviorally rather than emotionally.","Allow someone to be disappointed without withdrawing care.","Distinguish relational safety from emotional comfort.","Stop compensating privately for another person’s unaddressed responsibility.","Ask team members what remains difficult to say.","Establish transparent consequences and pathways for repair."],"leadershipStyleName":"The People-Centered Guide"},{"num":24,"name":"The Practical Pioneer","slug":"practical-pioneer","gifts":["catalyst","servant","enthusiast"],"essence":"To pioneer a new possibility, build its first tangible expression, and inspire others to participate in making it real.","section":"Section 6: The Groundbreakers (Balanced Triads · Catalyst-Led)","axisSignature":"1 Why · 1 How · 1 Who","websiteSummary":"The Practical Pioneer imagines a better way, builds its first tangible expression, and invites others into the adventure. At their best, they make innovation participatory and practical. Under stress, novelty replaces faithfulness, enthusiasm outruns capacity, and teams inherit the cost of unfinished beginnings.","sigStrengthName":"Participatory Innovation","sigStrengthDesc":"","sigParadox":"Generating momentum without abandoning what the momentum started","devQuestion":"Can I remain faithful when innovation becomes implementation and excitement becomes ordinary responsibility?","formationPractices":["Define the problem before announcing the innovation.","Set success, failure, and learning criteria for every pilot.","Limit the number of active experiments.","Ask who will own the work after launch.","Publicly name the cost and uncertainty.","Finish or formally close one initiative before beginning another.","Invite operational critique without labeling it negativity.","Celebrate maintenance and refinement as creative faithfulness."],"leadershipStyleName":"The Participatory Innovator"},{"num":25,"name":"The Compassionate Builder","slug":"compassionate-builder","gifts":["catalyst","servant","lover"],"essence":"To recognize the human suffering created by a broken reality, pioneer a more healing alternative, and build a tangible solution that restores dignity.","section":"Section 6: The Groundbreakers (Balanced Triads · Catalyst-Led)","axisSignature":"1 Why · 1 How · 1 Who","websiteSummary":"The Compassionate Builder feels the suffering created by what is broken, imagines a more humane possibility, and builds a tangible solution. At their best, they practice human-centered innovation that restores dignity and agency. Under stress, compassion becomes over-responsibility, innovation becomes rescuing, and relentless work replaces grief.","sigStrengthName":"Human-Centered Innovation","sigStrengthDesc":"","sigParadox":"Building from compassion without working to escape compassion’s grief","devQuestion":"Can I remain emotionally present to suffering without believing I must personally build the entire answer?","formationPractices":["Include affected people as co-designers with real authority.","Name the grief before proposing the solution.","Define the specific problem the project can address.","Ask whether building is replacing feeling.","Establish limits on personal work and availability.","Create a feedback process that does not depend upon gratitude.","Build in a way that increases local ownership.","Receive help before exhaustion makes it unavoidable.","Rest as an act of trust rather than a retreat from compassion."],"leadershipStyleName":"The Human-Centered Builder"},{"num":26,"name":"The Generous Pioneer","slug":"generous-pioneer","gifts":["catalyst","enthusiast","host"],"essence":"To pioneer a compelling new possibility, rally people around its promise, and mobilize the resources needed to bring it to life.","section":"Section 6: The Groundbreakers (Balanced Triads · Catalyst-Led)","axisSignature":"1 Why · 1 How · 1 Who","websiteSummary":"The Generous Pioneer imagines a bold new possibility, inspires people to believe in it, and mobilizes the resources required for launch. At their best, they practice catalytic investment that expands others’ agency. Under stress, enthusiasm overpromises, generosity seeks control, and innovation becomes attached to the founder’s identity.","sigStrengthName":"Catalytic Investment","sigStrengthDesc":"","sigParadox":"Generously launching the future without needing to own it","devQuestion":"Can I provide catalytic support without requiring the future to remain in my image?","formationPractices":["Define the problem before funding the solution.","Separate financial support from decision-making rights.","Require realistic stewardship plans for new initiatives.","Fund something without receiving public recognition.","Invite a trusted critic to evaluate the proposal.","Tell supporters the costs and uncertainties.","Establish review points before increasing investment.","Practice blessing an initiative that develops differently than imagined."],"leadershipStyleName":"The Catalytic Patron"},{"num":27,"name":"The Resourced Healer","slug":"resourced-healer","gifts":["catalyst","host","lover"],"essence":"To identify the conditions producing suffering, pioneer a more healing alternative, and build or fund the resources through which restoration can occur.","section":"Section 6: The Groundbreakers (Balanced Triads · Catalyst-Led)","axisSignature":"1 Why · 1 How · 1 Who","websiteSummary":"The Resourced Healer identifies conditions that sustain suffering, pioneers more humane responses, and builds or funds environments of restoration. At their best, they expand access, dignity, and agency. Under stress, compassion becomes rescuing, provision becomes control, and the healer assumes responsibility for another person’s recovery.","sigStrengthName":"Restorative Institution-Building","sigStrengthDesc":"","sigParadox":"Resourcing healing without controlling another person’s recovery","devQuestion":"Can I create conditions for healing without claiming ownership of the healing process?","formationPractices":["Include recipients in governance and design.","Review whether funding conditions preserve agency.","Practice accompanying without rescuing.","Distinguish relapse or slow progress from failure.","Receive personal care rather than only providing it.","Fund approaches that do not increase your influence.","Build transparent outcome and feedback systems.","Ask whether the institution remains more committed to healing than survival."],"leadershipStyleName":"The Restorative Founder"},{"num":28,"name":"The Meticulous Motivator","slug":"meticulous-motivator","gifts":["servant","erudite","enthusiast"],"essence":"To make difficult learning and skilled work approachable through accurate instruction, practical assistance, and encouraging reinforcement.","section":"Section 7: The Wise Stewards (Balanced Triads · Erudite-Led)","axisSignature":"1 Why · 1 How · 1 Who","websiteSummary":"The Meticulous Motivator combines accurate knowledge, practical instruction, and encouraging reinforcement to make mastery approachable. At their best, people learn difficult things without feeling small. Under stress, detail overwhelms, help becomes rescuing, and encouragement obscures necessary correction.","sigStrengthName":"Encouraging Mastery","sigStrengthDesc":"","sigParadox":"Helping people succeed without making their success dependent upon your help","devQuestion":"Can I support a learner through difficulty without removing the struggle through which mastery develops?","formationPractices":["Ask the learner to demonstrate before offering help.","Give concise, behaviorally specific feedback.","Allow manageable frustration.","Reduce assistance as competence increases.","Identify the minimum knowledge required for the next step.","Separate being kind from being approving.","Ask learners to evaluate their own performance first.","Celebrate independence more than gratitude."],"leadershipStyleName":"The Encouraging Instructor"},{"num":29,"name":"The Wise Caretaker","slug":"wise-caretaker","gifts":["servant","erudite","lover"],"essence":"To offer care that accurately understands the need, responds with practical competence, and preserves the dignity of the person receiving it.","section":"Section 7: The Wise Stewards (Balanced Triads · Erudite-Led)","axisSignature":"1 Why · 1 How · 1 Who","websiteSummary":"The Wise Caretaker combines careful understanding, emotional attunement, and practical service to provide care that genuinely fits. At their best, people feel both known and competently supported. Under stress, care becomes over-analysis, service becomes self-erasure, and personal needs remain hidden until exhaustion takes over.","sigStrengthName":"Discerning Care","sigStrengthDesc":"The Wise Caretaker often recognizes the difference between what a person requests, what they appear to need, and what will genuinely support flourishing.","sigParadox":"Understanding everyone’s needs while remaining silent about their own","devQuestion":"Can I believe that my needs deserve the same careful attention I give to others?","formationPractices":["State one personal need each day.","Ask permission before offering help.","Decide what information is sufficient for action.","Use a team for complex or recurring care.","Practice receiving without immediately serving.","Communicate limits before exhaustion.","Let another person make a choice you would not recommend.","Apply the same compassion and discernment inward."],"leadershipStyleName":"The Discerning Caregiver"},{"num":30,"name":"The Prudent Mentor","slug":"prudent-mentor","gifts":["erudite","enthusiast","host"],"essence":"To recognize potential wisely, strengthen it through encouragement and insight, and provide the opportunities and resources through which it can flourish.","section":"Section 7: The Wise Stewards (Balanced Triads · Erudite-Led)","axisSignature":"1 Why · 1 How · 1 Who","websiteSummary":"The Prudent Mentor recognizes potential, strengthens it through wise encouragement, and provides concrete opportunities for development. At their best, investment expands another person’s freedom and contribution. Under stress, guidance becomes prescription, resources become leverage, and mentoring produces emotional debt.","sigStrengthName":"Empowering Sponsorship","sigStrengthDesc":"The Prudent Mentor can identify promising people and give them the support needed to develop beyond their current circumstances.","sigParadox":"Investing deeply without owning the return","devQuestion":"Can I help someone flourish into their calling rather than flourish according to my preferred image?","formationPractices":["Ask the mentee to define success.","Clarify all conditions before providing resources.","Invest anonymously when possible.","Sponsor someone outside your familiar social pattern.","Invite feedback about the relational power dynamic.","Bless a path you would not personally choose.","Celebrate independence and reduced reliance.","Evaluate whether access is being distributed fairly."],"leadershipStyleName":"The Developmental Sponsor"},{"num":31,"name":"The Benevolent Counselor","slug":"benevolent-counselor","gifts":["erudite","host","lover"],"essence":"To offer compassionate wisdom together with the tangible resources and relational support that help people rebuild their lives.","section":"Section 7: The Wise Stewards (Balanced Triads · Erudite-Led)","axisSignature":"1 Why · 1 How · 1 Who","websiteSummary":"The Benevolent Counselor pairs compassionate wisdom with tangible resources that help people rebuild. At their best, counsel and provision increase dignity, responsibility, and freedom. Under stress, wisdom becomes prescription, generosity produces obligation, and care keeps people dependent.","sigStrengthName":"Resourced Wisdom","sigStrengthDesc":"","sigParadox":"Providing meaningful help without becoming the owner of another person’s next step","devQuestion":"Can I offer wisdom and resources without requiring the recipient to use them exactly as I would?","formationPractices":["Ask the recipient to define the desired outcome.","Clarify all conditions before offering resources.","Separate counsel from material support where appropriate.","Offer options rather than a single required path.","Establish boundaries around repeated assistance.","Review whether support is increasing agency.","Practice giving without requiring access or gratitude.","Build relationships not organized around the helping role."],"leadershipStyleName":"The Restorative Advisor"},{"num":32,"name":"The Inspirational Implementer","slug":"inspirational-implementer","gifts":["servant","enthusiast","strategist"],"essence":"To guide teams toward meaningful results by combining clear direction, practical execution, and an encouraging culture of shared accomplishment.","section":"Section 8: The Kingdom Builders (Balanced Triads · Strategist-Led)","axisSignature":"1 Why · 1 How · 1 Who","websiteSummary":"The Inspirational Implementer combines strategic direction, practical execution, and encouraging team culture. At their best, people understand the goal, enjoy contributing, and deliver together. Under stress, positivity hides problems, service becomes over-functioning, and accountability is delayed.","sigStrengthName":"Energized Execution","sigStrengthDesc":"","sigParadox":"Maintaining morale without using positivity to hide problems","devQuestion":"Can I preserve hope while naming clearly what is not working?","formationPractices":["Name one difficult reality before offering encouragement.","Clarify every task’s owner and deadline.","Stop doing one task that belongs to someone else.","Ask the team to identify what is not working.","Replace generic praise with specific recognition.","Build recovery time into project completion.","Reduce scope before increasing personal sacrifice.","Address underperformance while the relationship is still warm."],"leadershipStyleName":"The Morale-Building Operator"},{"num":33,"name":"The Protective Architect","slug":"protective-architect","gifts":["servant","strategist","lover"],"essence":"To design and build effective systems while protecting the dignity, capacity, and well-being of the people doing the work.","section":"Section 8: The Kingdom Builders (Balanced Triads · Strategist-Led)","axisSignature":"1 Why · 1 How · 1 Who","websiteSummary":"The Protective Architect builds effective systems while guarding the dignity and capacity of the people within them. At their best, excellence and care strengthen one another. Under stress, protection becomes control, service becomes over-functioning, and people remain dependent rather than empowered.","sigStrengthName":"Humane Systems Design","sigStrengthDesc":"The Protective Architect can create environments in which excellence and well-being reinforce rather than oppose one another.","sigParadox":"Protecting people without taking away their ownership of difficult work","devQuestion":"Can I protect people from exploitation without protecting them from every challenge through which competence and resilience develop?","formationPractices":["Include frontline contributors in system design.","Define the difference between difficult work and harmful overload.","Return one responsibility you have absorbed.","Delegate authority alongside tasks.","Make workload visible across the team.","State hard expectations with compassion.","Let someone learn through a recoverable mistake.","Evaluate both outcomes and human impact."],"leadershipStyleName":"The Humane Systems Builder"},{"num":34,"name":"The Kingdom Cultivator","slug":"kingdom-cultivator","gifts":["enthusiast","host","strategist"],"essence":"To grow healthy organizations by aligning compelling purpose, generous resources, strategic structure, and a culture in which people want to participate.","section":"Section 8: The Kingdom Builders (Balanced Triads · Strategist-Led)","axisSignature":"1 Why · 1 How · 1 Who","websiteSummary":"The Kingdom Cultivator aligns purpose, resources, strategy, and culture so organizations can flourish over time. At their best, growth increases shared participation and life. Under stress, culture becomes managed, resources reinforce loyalty, and organizational optics eclipse honest reality.","sigStrengthName":"Organizational Cultivation","sigStrengthDesc":"","sigParadox":"Cultivating a living culture without managing every expression of it","devQuestion":"Can I shape the conditions for healthy culture without controlling what people are allowed to think, feel, or say?","formationPractices":["Create a confidential channel for dissent.","Measure health using more than growth and participation.","Ask where public culture and private experience diverge.","Allocate resources through transparent criteria.","communicate one meaningful uncertainty honestly.","Let another leader shape culture differently.","Prune an initiative that no longer serves the mission.","Conduct listening sessions without defending the organization.","Celebrate faithfulness that is not publicly impressive."],"leadershipStyleName":"The Organizational Cultivator"},{"num":35,"name":"The Benevolent Leader","slug":"benevolent-leader","gifts":["host","strategist","lover"],"essence":"To lead people toward a meaningful future while providing the resources, protection, and relational care that help them flourish along the journey.","section":"Section 8: The Kingdom Builders (Balanced Triads · Strategist-Led)","axisSignature":"1 Why · 1 How · 1 Who","websiteSummary":"The Benevolent Leader combines strategic direction, generous provision, and compassionate protection. At their best, people receive the support and authority needed to flourish. Under stress, care becomes paternalism, resources create dependence, and protection prevents the struggle through which maturity develops. Appendix","sigStrengthName":"Resourced, People-Centered Direction","sigStrengthDesc":"","sigParadox":"Providing security without making people dependent upon the provider","devQuestion":"Can I care enough to let people carry real responsibility, face necessary struggle, and become less dependent upon me?","formationPractices":["Return one decision to the person who should own it.","Ask whether each provision increases capacity.","Let a recoverable consequence remain.","Publish transparent resource-allocation criteria.","Give emerging leaders real authority.","Resist solving a problem before others attempt it.","Invite critique from people who do not depend upon your resources.","Develop a succession plan.","Practice presence without intervention."],"leadershipStyleName":"The Provisioning Shepherd"}];
window.QUESTIONS = {"likert":[{"id":1,"text":"I naturally think in terms of long-range goals and strategic plans.","gift":"strategist"},{"id":2,"text":"I am energized by challenging the status quo to bring about necessary change.","gift":"catalyst"},{"id":3,"text":"I feel most satisfied when I have completed a practical task with excellence.","gift":"servant"},{"id":4,"text":"Building many positive, encouraging relationships is one of my highest priorities.","gift":"enthusiast"},{"id":5,"text":"My primary drive is to create an environment where people feel emotionally safe and accepted.","gift":"lover"},{"id":6,"text":"I feel a deep need for quiet time alone to think, process, and recharge.","gift":"erudite"},{"id":7,"text":"I am a good manager of resources (time, money, people) and use them wisely.","gift":"host"},{"id":8,"text":"I am driven to build systems and structures that create order and ensure long-term success, and will see my plans come to fruition, even if it takes days, months, or years.","gift":"strategist"},{"id":9,"text":"When I see a problem, my first instinct is to identify the root truth, even if it's uncomfortable.","gift":"catalyst"},{"id":10,"text":"People describe me as meticulous and conscientious in the tasks I complete for them.","gift":"servant"},{"id":11,"text":"I often verbally affirm others' potential and strengths in all spheres of my life.","gift":"enthusiast"},{"id":12,"text":"I have a deep, intuitive sense of the emotional state of others and feel moved to undo their aloneness in places of pain.","gift":"lover"},{"id":13,"text":"Before I accept something as fact, I feel compelled to research and validate it for myself.","gift":"erudite"},{"id":14,"text":"I get great joy, and am gifted at being hospitable and making people feel comfortable and cherished.","gift":"host"},{"id":15,"text":"I am a natural leader and take a long-term view of leadership and the development of others.","gift":"strategist"},{"id":16,"text":"I am more concerned with integrity and authenticity than with keeping everyone comfortable.","gift":"catalyst"},{"id":17,"text":"It frustrates me when I see people not doing their fair share of the work.","gift":"servant"},{"id":18,"text":"I am energized by rallying people together around a hopeful, positive vision.","gift":"enthusiast"},{"id":19,"text":"I am known for my long-suffering unconditional love and acceptance.","gift":"lover"},{"id":20,"text":"I research deeper and more complex topics than most others just for the sake of knowing the information.","gift":"erudite"},{"id":21,"text":"I usually have what others need, such as snacks, drinks, or other useful items, such as tissues, before others know that they need it.","gift":"host"},{"id":22,"text":"I have goals in place and don't like to deviate from them until they are completed.","gift":"strategist"},{"id":23,"text":"I am a pioneering spirit, always having new and innovative ideas and solutions.","gift":"catalyst"},{"id":24,"text":"People can count on me to be dependable and to finish the tasks I start.","gift":"servant"},{"id":25,"text":"I feel fulfilled when I can inspire and rally others to become passionate about what I am most passionate about at a given time.","gift":"enthusiast"},{"id":26,"text":"I tend to deescalate conflict and am often a peacemaker.","gift":"lover"},{"id":27,"text":"I am frustrated by superficial conversations that don't interest me and prefer deep, intellectually stimulating discussions.","gift":"erudite"},{"id":28,"text":"I am super resourceful.","gift":"host"},{"id":29,"text":"I have little patience for activities that do not align with the main goal or vision.","gift":"strategist"},{"id":30,"text":"I feel compelled to speak up against injustice or hypocrisy.","gift":"catalyst"},{"id":31,"text":"I show my love for others by taking practical action to meet their tangible needs.","gift":"servant"},{"id":32,"text":"I am naturally optimistic and believe the best about people and situations.","gift":"enthusiast"},{"id":33,"text":"I can become emotionally overwhelmed because I sometimes absorb the pain of others.","gift":"lover"},{"id":34,"text":"I prefer to be alone studying the things I am passionate about or explaining them to interested individuals.","gift":"erudite"},{"id":35,"text":"I enjoy stewarding and multiplying resources so I can be more generous.","gift":"host"},{"id":36,"text":"My motto could be, \"Good leaders create a vision, articulate the vision, passionately own the vision, and relentlessly drive it to completion.\" - Jack Welch.","gift":"strategist"},{"id":37,"text":"I have a strong inner sense of what is right and wrong.","gift":"catalyst"},{"id":38,"text":"I often notice and move to meet the practical needs in a room before anyone else does.","gift":"servant"},{"id":39,"text":"I have a strong intuition about interpersonal dynamics and work to build bridges between people.","gift":"enthusiast"},{"id":40,"text":"I am fiercely protective of the vulnerable and instinctively shield them from harm.","gift":"lover"},{"id":41,"text":"I am not easily swayed by peer pressure or others' approval, as I have strong convictions and desires.","gift":"erudite"},{"id":42,"text":"I view the resources I have as something I've been entrusted with for the benefit of others.","gift":"host"},{"id":43,"text":"I excel at architecting a long-term plan and then delegating to the right people to bring that vision to reality.","gift":"strategist"},{"id":44,"text":"I am compelled to challenge the status quo and uproot broken systems to achieve radical, not just incremental, transformation.","gift":"catalyst"},{"id":45,"text":"I feel most fulfilled after a hard day of tangible, productive work.","gift":"servant"},{"id":46,"text":"I'm energized by rallying people together, using fun and celebration to build connections and inspire a shared sense of optimism.","gift":"enthusiast"},{"id":47,"text":"I feel most loved when someone listens to me with their whole heart and understands my feelings.","gift":"lover"},{"id":48,"text":"I feel most loved when someone engages me in a deeply intellectual conversation.","gift":"erudite"},{"id":49,"text":"I constantly am thinking about how myself and others can engage in wise financial stewardship.","gift":"host"}],"forcedChoice":[{"id":50,"stem":"I am more driven to...","a":"Challenge a broken system to get to the truth.","b":"Diligently complete the tasks needed to keep the current system running.","giftA":"catalyst","giftB":"servant"},{"id":51,"stem":"I am more driven to...","a":"Inspire a group of people with a hopeful, positive vision.","b":"Confront a group with an uncomfortable reality that leads to transformation.","giftA":"enthusiast","giftB":"catalyst"},{"id":52,"stem":"I am more driven to...","a":"Speak a hard truth, even if it causes emotional discomfort.","b":"Protect someone's feelings, even if it means avoiding a hard truth.","giftA":"catalyst","giftB":"lover"},{"id":53,"stem":"When leading, my priority is...","a":"Ensuring the team stays the course on a well-thought-out master plan.","b":"Allowing for disruptive innovation that might improve upon the master plan.","giftA":"strategist","giftB":"catalyst"},{"id":54,"stem":"I am more drawn to...","a":"A deep, analytical dive into a complex subject.","b":"A bold, pioneering adventure that challenges my limits.","giftA":"erudite","giftB":"catalyst"},{"id":55,"stem":"My focus is more on...","a":"Wisely stewarding resources to fund a bold, risky, but potentially revolutionary idea or adventure.","b":"Wisely stewarding resources to ensure long-term stability and security.","giftA":"catalyst","giftB":"host"},{"id":56,"stem":"I prefer to show support by...","a":"Cheerfully rallying and encouraging the person.","b":"Practically helping them with their to-do list.","giftA":"enthusiast","giftB":"servant"},{"id":57,"stem":"I believe love is best expressed by...","a":"Providing tangible help and practical solutions.","b":"Providing a safe, empathetic presence for someone's emotions.","giftA":"servant","giftB":"lover"},{"id":58,"stem":"In a group project, I focus on...","a":"The long-term vision and overall strategy.","b":"The immediate tasks that need to be done right now.","giftA":"strategist","giftB":"servant"},{"id":59,"stem":"I am more likely to be...","a":"Frustrated by inaction and analysis paralysis.","b":"Frustrated by rushed decisions made without thorough research.","giftA":"servant","giftB":"erudite"},{"id":60,"stem":"When giving a gift, I am more concerned with...","a":"Ensuring everyone contributes fairly and the gift is practical.","b":"Ensuring the gift is generous, empowering, and makes the recipient feel cherished.","giftA":"servant","giftB":"host"},{"id":61,"stem":"A healthy relationship requires...","a":"Deep emotional safety and unconditional acceptance.","b":"Uplifting joy and mutual celebration.","giftA":"lover","giftB":"enthusiast"},{"id":62,"stem":"I am more inclined to...","a":"Let my decisions be guided by the emotional needs of the people involved.","b":"Let my decisions be guided by the objective goals of the plan.","giftA":"lover","giftB":"strategist"},{"id":63,"stem":"My approach to problems is more...","a":"Analytical and logical, based on verifiable facts.","b":"Empathetic and intuitive, based on people's feelings.","giftA":"erudite","giftB":"lover"},{"id":64,"stem":"When considering a large donation, I prioritize...","a":"The immediate emotional relief and comfort it will bring to an individual.","b":"The long-term strategic impact and stewardship of the organization receiving it.","giftA":"lover","giftB":"host"},{"id":65,"stem":"I am more energized by...","a":"Creating a detailed, systematic plan to achieve a goal.","b":"Inspiring and rallying a team towards a shared objective.","giftA":"strategist","giftB":"enthusiast"},{"id":66,"stem":"I find it more important to be...","a":"Intellectually rigorous and precise.","b":"Relationally warm and encouraging.","giftA":"erudite","giftB":"enthusiast"},{"id":67,"stem":"When planning an event, I focus more on...","a":"The relational atmosphere and ensuring people have fun and connect.","b":"The budget and resources, ensuring a high-quality experience through wise stewardship.","giftA":"enthusiast","giftB":"host"},{"id":68,"stem":"My leadership style is more focused on...","a":"Architecting brilliant, long-term systems and plans.","b":"Patiently mentoring individuals to help them master a subject.","giftA":"strategist","giftB":"erudite"},{"id":69,"stem":"I would rather...","a":"Build a detailed budget and investment plan.","b":"Build a comprehensive research paper with extensive citations.","giftA":"host","giftB":"erudite"},{"id":70,"stem":"When making a big decision, I trust...","a":"A strategic plan that lays out the path to a future goal.","b":"A prudent financial plan that ensures resources are used wisely.","giftA":"strategist","giftB":"host"}],"scenarios":[{"id":1,"stem":"A volunteer project you are on is missing deadlines and team morale is plummeting.","options":["Call an emergency meeting to re-architect the master plan, clarify the vision, and re-delegate tasks.","Privately check in with each team member to see how they are feeling, creating a safe space for them to voice concerns.","Find the biggest practical bottleneck and just start doing the work yourself to get momentum going again.","Directly confront the unspoken issue you believe is causing the failure, pushing for honesty to clear the air."],"gifts":["strategist","lover","servant","catalyst"]},{"id":2,"stem":"A close friend is devastated after being laid off from their job.","options":["Immediately start reminding them of their strengths, telling them this is a setup for a comeback, and painting a positive picture of their future.","Offer a significant and thoughtful financial gift to cover their expenses for a month, empowering them to search for a new job without stress.","Spend hours with them researching the job market, analyzing their resume, and helping them build a logical, data-driven plan for their job search.","Sit with them in their grief, listen without judgment, and let them know you are there for them no matter what, validating their feelings of loss and fear."],"gifts":["enthusiast","host","erudite","lover"]},{"id":3,"stem":"You are on the planning committee for a large community-wide charity event.","options":["Take charge of the budget and fundraising, ensuring every dollar is used wisely to create a high-quality, memorable, and generous experience.","Volunteer to be the MC or lead the welcoming committee, focusing on creating a fun, high-energy, and relational atmosphere.","Take on the role of overall event coordinator, developing the master timeline, defining roles for all teams, and making sure the event achieves its objective.","Sign up for the setup and teardown crew, quietly ensuring all the practical, hands-on work gets done with excellence."],"gifts":["host","enthusiast","strategist","servant"]},{"id":4,"stem":"You receive an unexpected financial windfall of $5,000.","options":["Use it to fund a bold, adventurous trip, or invest it in a high-risk, high-reward idea you believe in.","Put it toward a major long-term goal (like a down payment or a business plan), allocating it according to your life strategy.","Immediately think of a person or cause that could benefit and give a generous, empowering gift.","Spend it on a fantastic party or group vacation to create a lasting, joyful memory with the people you love."],"gifts":["catalyst","strategist","host","enthusiast"]},{"id":5,"stem":"You discover that a long-standing policy in your church or workplace is quietly hurting the very people it was meant to serve.","options":["Name the problem openly and press leadership for immediate, meaningful change, even if it ruffles feathers.","Quietly begin helping the people affected in practical, tangible ways while the debate plays out.","Research the policy's history and gather the data needed to build a careful, well-documented case for reform.","Seek out those who have been hurt, listen to their stories, and make sure no one carries the pain alone."],"gifts":["catalyst","servant","erudite","lover"]},{"id":6,"stem":"Your team is asked to launch a brand-new initiative from scratch, with wide freedom in how to begin.","options":["Challenge the assumptions behind the old way of doing things and cast a bold, disruptive vision for what this could become.","Study how others have done it—gathering research, best practices, and lessons learned before anything is decided.","Architect the master plan: phases, roles, milestones, and a clear picture of success at the end.","Take charge of resourcing it—securing the budget, space, and supplies so the team launches generously provided for."],"gifts":["catalyst","erudite","strategist","host"]},{"id":7,"stem":"A new family joins your community and seems overwhelmed by the transition.","options":["Show up with practical help: meals, moving boxes, school runs—whatever lightens their load this week.","Welcome them warmly, introduce them to everyone, and speak hope and excitement over their new chapter.","Make unhurried space to hear their story and keep checking in on how they are really doing.","Patiently orient them—explaining how everything works and thoroughly answering every question they have."],"gifts":["servant","enthusiast","lover","erudite"]}],"giftMax":{"catalyst":68,"servant":68,"enthusiast":68,"lover":68,"strategist":68,"erudite":68,"host":68}};
window.LOW_GIFTS = {"catalyst": {"struggle": "With the Catalyst's fire burning low, you rarely feel an inner demand to confront what is broken. You may tolerate dysfunctional systems and unspoken problems far longer than is healthy, keep the peace when the moment calls for holy disruption, and feel blindsided when change finally forces itself on you. Necessary conflict can feel like failure rather than faithfulness, so hard conversations get postponed until they become harder ones.", "friction": "People who lead with Prophecy can feel overwhelming to you. Their directness lands like an attack and their urgency like recklessness, and you may quietly write them off as harsh—while they read your patience as complicity with what is broken. When they press for the truth behind a problem, you may hear accusation where they intend rescue.", "bridges": ["When a Catalyst confronts, listen for the love of truth underneath the heat—ask “What are you seeing that I’m not?” before defending.", "Practice naming one broken thing out loud each week; borrowed courage grows.", "Don’t ask a Catalyst to soften the message—ask them to help you build what should replace the broken thing."]}, "servant": {"struggle": "With Service running quiet, practical needs don’t call out to you the way they do to others. Tasks pile up or drift to whoever seems willing, the logistics beneath every good idea get underestimated, and the invisible labor that keeps your home, team, or church running can go unnoticed until it stops. You may carry a reputation for being above the mundane that quietly costs you trust.", "friction": "People who lead with Service often feel unseen around you. Your talk-first instinct frustrates their do-first nature; they feel used when their help is assumed and unthanked, while you may find their focus on tasks small when bigger things are on the table. Your unfinished commitments read to them as broken promises.", "bridges": ["Thank the Servant specifically—name the task, not just the person.", "Before casting the next vision, finish one tangible thing you said you’d do.", "Ask “What needs doing?” and take a visible piece of it yourself."]}, "erudite": {"struggle": "With the Erudite’s hunger dimmed, deep study rarely feels worth the time. You may build strong opinions on thin foundations, decide from intuition alone, and grow impatient with the slow work of truly understanding something. That leaves you vulnerable to shallow answers and confident errors—and prone to repeating problems that an evening of honest study would have prevented.", "friction": "People who lead with Teaching can exhaust you. Their questions feel like doubt, their precision like pedantry, their “let me research it” like delay. Meanwhile they experience your speed as carelessness and your certainty as unearned. Conversations stall when nuance—their native language—gets waved away.", "bridges": ["Bring an Erudite into decisions early, not for rubber-stamping afterward.", "Let them fully vet one significant choice each season—and notice what it saves you.", "Ask “What am I missing?” and genuinely wait for the answer."]}, "enthusiast": {"struggle": "With Encouragement running low, affirmation isn’t your reflex. Relationships can run on function rather than celebration, wins slip past unmarked, and the people closest to you may quietly wonder whether you notice them at all. Without a native supply of hope, setbacks weigh heavier and vision is harder to sustain—for you and for anyone following you.", "friction": "People who lead with Encouragement may strike you as noisy or excessive, and their need for affirmation can feel needy. But your reserve reads to them as disapproval, and they wilt in ways you don’t intend. When they celebrate you, you may deflect—which lands as rejection of the very gift they most love to give.", "bridges": ["Name one strength out loud, per person, per gathering. It will feel like too much; it isn’t.", "Receive an Enthusiast’s praise with a simple thank-you instead of a deflection.", "Let celebration count as real work—it is how belonging gets built."]}, "host": {"struggle": "With Giving quiet in you, resources feel like background details rather than ministry. Generosity happens in bursts instead of rhythms, margins and provision go unplanned, and hospitality can feel like a chore—so gathering people defaults to somebody else. Opportunities that needed seed money, a meal, or an open home pass by unclaimed.", "friction": "People who lead with Giving can seem preoccupied with money, logistics, and stewardship, and their carefulness may read to you as stinginess. But your improvidence genuinely stresses them, and when their quiet provision goes unnoticed they feel taken for granted. Asking them to “just trust” without a plan asks them to violate their design.", "bridges": ["Honor stewardship as a spiritual gift, not accounting—thank the Host for what their planning made possible.", "Schedule one act of intentional generosity each month so giving doesn’t depend on mood.", "Invite a Host to build your budget or event plan with you—and watch the anxiety drop."]}, "strategist": {"struggle": "With Leadership’s long view dimmed, the horizon blurs. Seasons turn busy but directionless, goals drift, and you can wake up wondering how you ended up here. Other people’s plans feel confining, so you improvise—and some of those improvisations become messes a simple map would have prevented. Follow-through on multi-step commitments is the quiet casualty.", "friction": "People who lead with Leadership can feel controlling to you—their structures like cages, their questions about “the plan” like tests you didn’t study for. Meanwhile your spontaneity registers to them as a threat to the mission, and your last-minute pivots undo work they invested in. They don’t need you to become them; they need warning before you swerve.", "bridges": ["Give Strategists the courtesy of a heads-up before changing course.", "Borrow their gift: set one 90-day goal and let them help you sequence it.", "Ask “Where is this going?” before you start—then actually aim."]}, "lover": {"struggle": "With Mercy running quiet, the emotional current of a room flows beneath your notice. You reach for solutions when people need presence, miss the wound behind the behavior, and can leave vulnerable people guarded around you without knowing why. Your own feelings, left unprocessed, tend to leak out sideways as irritation or withdrawal.", "friction": "People who lead with Mercy may seem inefficient to you—slow to decide, quick to feel, forever circling back to how everyone is doing. But your fixes land on them as dismissal, and your pace tramples places that needed gentleness. They need safety before solutions; you lead with solutions.", "bridges": ["Ask “Do you want comfort or counsel?” before offering either.", "Sit with someone’s pain for five full minutes before solving anything.", "Let a Lover teach you what listening without fixing looks like—then practice on them."]}};
window.INTENSITY = function(score){
  if (score >= 85) return { label: 'Very High', cls: 'vh' };
  if (score >= 61) return { label: 'High', cls: 'h' };
  if (score >= 41) return { label: 'Medium', cls: 'm' };
  if (score >= 16) return { label: 'Low', cls: 'l' };
  return { label: 'Very Low', cls: 'vl' };
};
/* Official scoring (Unified Scoring Instructions), normalized per gift maximum.
   state = { likert: {qid: 1..5}, fc: {qid: 'a'|'b'}, sjt: {sid: {most: idx, least: idx}} } */
window.computeScores = function(state){
  var Q = window.QUESTIONS, ORDER = window.GIFT_ORDER;
  var raw = {}, likertSub = {}, fcSub = {};
  ORDER.forEach(function(g){ raw[g]=0; likertSub[g]=0; fcSub[g]=0; });
  Q.likert.forEach(function(q){
    var r = state.likert[q.id] || 1;
    raw[q.gift] += (r-1); likertSub[q.gift] += (r-1);
  });
  Q.forcedChoice.forEach(function(q){
    var pick = state.fc[q.id];
    if (pick === 'a') { raw[q.giftA] += 4; fcSub[q.giftA] += 4; }
    if (pick === 'b') { raw[q.giftB] += 4; fcSub[q.giftB] += 4; }
  });
  Q.scenarios.forEach(function(s){
    var st = state.sjt[s.id] || {};
    s.gifts.forEach(function(g, idx){
      if (idx === st.most) raw[g] += 4;
      else if (idx === st.least) raw[g] += 0;
      else raw[g] += 1;
    });
  });
  var scores = {};
  ORDER.forEach(function(g){
    scores[g] = Math.max(0, Math.min(100, Math.round(raw[g] / Q.giftMax[g] * 100)));
  });
  var ranked = ORDER.slice().sort(function(a,b){
    return (scores[b]-scores[a]) || (likertSub[b]-likertSub[a]) || (fcSub[b]-fcSub[a]) || (ORDER.indexOf(a)-ORDER.indexOf(b));
  });
  var top3 = ranked.slice(0,3);
  var tieAtCut = scores[ranked[2]] === scores[ranked[3]];
  var arch = window.ARCHETYPES.find(function(a){
    return a.gifts.slice().sort().join() === top3.slice().sort().join();
  });
  return { scores: scores, raw: raw, ranked: ranked, top3: top3,
           archetype: arch ? arch.slug : null, tieAtCut: tieAtCut, date: new Date().toISOString() };
};
